// OpenAI Realtime API: Node.js WebSocket client
// npm install ws

const WebSocket = require('ws');

const API_KEY = process.env.OPENAI_API_KEY;
const URL = 'wss://api.openai.com/v1/realtime?model=gpt-4o-realtime-preview';

const ws = new WebSocket(URL, {
  headers: {
    Authorization: `Bearer ${API_KEY}`,
    'OpenAI-Beta': 'realtime=v1',
  },
});

ws.on('open', () => {
  console.log('Connected to Realtime API');

  // Configure session on open
  ws.send(JSON.stringify({
    type: 'session.update',
    session: {
      modalities: ['audio', 'text'],
      instructions: 'You are a helpful voice assistant.',
      voice: 'shimmer',
      input_audio_format: 'pcm16',
      output_audio_format: 'pcm16',
      turn_detection: {
        type: 'server_vad',
        silence_duration_ms: 600,
        threshold: 0.5,
      },
      input_audio_transcription: { model: 'whisper-1' },
    },
  }));

  // Simulate sending a short pre-recorded audio clip
  // In production: stream from microphone in 100ms chunks
  const audioBase64 = loadAudioBase64('greeting.pcm'); // your PCM loader
  ws.send(JSON.stringify({
    type: 'input_audio_buffer.append',
    audio: audioBase64,
  }));

  // Manually commit the buffer (disable server_vad to use manual mode)
  // ws.send(JSON.stringify({ type: 'input_audio_buffer.commit' }));
  // ws.send(JSON.stringify({ type: 'response.create' }));
});

const audioChunks = [];

ws.on('message', (data) => {
  const event = JSON.parse(data);

  switch (event.type) {
    case 'session.created':
      console.log('Session ready:', event.session.id);
      break;

    case 'input_audio_buffer.speech_started':
      console.log('Speech detected...');
      break;

    case 'response.audio.delta':
      // Accumulate audio chunks for playback
      audioChunks.push(Buffer.from(event.delta, 'base64'));
      break;

    case 'response.audio_transcript.delta':
      process.stdout.write(event.delta);
      break;

    case 'response.done':
      console.log('\nResponse complete.');
      // audioChunks now contains the full PCM response
      const fullAudio = Buffer.concat(audioChunks);
      require('fs').writeFileSync('response.pcm', fullAudio);
      ws.close();
      break;

    case 'error':
      console.error('API error:', event.error);
      ws.close();
      break;
  }
});

ws.on('close', () => console.log('Session closed'));

function loadAudioBase64(filename) {
  // Returns a base64-encoded PCM16 24kHz mono file
  const buf = require('fs').readFileSync(filename);
  return buf.toString('base64');
}
